import Anthropic from '@anthropic-ai/sdk';
import { VexClient, VexVerificationError } from 'vex-sdk';

const anthropic = new Anthropic({ apiKey: process.env.ANTHROPIC_API_KEY });
const vex = new VexClient({ apiKey: process.env.VEX_API_KEY, framework: 'claude-tool-use' });

const tools: Anthropic.Tool[] = [
  {
    name: 'get_customer_data',
    description: 'Retrieve customer account information',
    input_schema: {
      type: 'object' as const,
      properties: {
        customer_id: { type: 'string' },
        include_billing: { type: 'boolean' }
      },
      required: ['customer_id']
    }
  },
  {
    name: 'update_subscription',
    description: 'Update a customer subscription plan',
    input_schema: {
      type: 'object' as const,
      properties: {
        customer_id: { type: 'string' },
        plan_id: { type: 'string' },
        effective_date: { type: 'string' }
      },
      required: ['customer_id', 'plan_id']
    }
  }
];

async function executeToolCall(toolName: string, toolInput: Record<string, unknown>): Promise<string> {
  // Your actual tool execution logic
  if (toolName === 'get_customer_data') {
    return JSON.stringify({ customer_id: toolInput.customer_id, plan: 'basic', status: 'active' });
  }
  if (toolName === 'update_subscription') {
    return JSON.stringify({ success: true, new_plan: toolInput.plan_id });
  }
  throw new Error(`Unknown tool: ${toolName}`);
}

async function runVerifiedAgentLoop(userMessage: string): Promise<string> {
  const messages: Anthropic.MessageParam[] = [
    { role: 'user', content: userMessage }
  ];

  while (true) {
    const rawResponse = await anthropic.messages.create({
      model: 'claude-opus-4-5',
      max_tokens: 4096,
      tools,
      messages
    });

    // Verify each response before processing tool_use blocks
    let verifiedResponse: Anthropic.Message;
    try {
      verifiedResponse = await vex.verify(rawResponse, {
        toolsProvided: tools.map(t => t.name),
        turnNumber: messages.length,
        checkSchemaConformance: true,
        checkParallelConflicts: true
      });
    } catch (err) {
      if (err instanceof VexVerificationError) {
        console.error(`Vex blocked: ${err.failureMode}`, err.details);
        return `Agent stopped: safety verification failed at turn ${messages.length / 2}`;
      }
      throw err;
    }

    if (verifiedResponse.stop_reason === 'end_turn') {
      const textBlock = verifiedResponse.content.find(b => b.type === 'text');
      return textBlock && textBlock.type === 'text' ? textBlock.text : 'No response generated';
    }

    if (verifiedResponse.stop_reason === 'tool_use') {
      const toolResults: Anthropic.ToolResultBlockParam[] = [];

      for (const block of verifiedResponse.content) {
        if (block.type === 'tool_use') {
          const result = await executeToolCall(block.name, block.input as Record<string, unknown>);
          toolResults.push({
            type: 'tool_result',
            tool_use_id: block.id,
            content: result
          });
        }
      }

      messages.push({ role: 'assistant', content: verifiedResponse.content });
      messages.push({ role: 'user', content: toolResults });
    }
  }
}

// Run the verified agent
runVerifiedAgentLoop('Upgrade customer C-12345 to the Pro plan starting next month')
  .then(result => console.log('Agent result:', result))
  .catch(console.error);

import anthropic
import vex_sdk as vex
from vex_sdk.exceptions import VexVerificationError, VexActionBlockedError
import base64

client = anthropic.Anthropic()
vex_client = vex.Client(
    api_key="your-vex-api-key",
    framework="claude-computer-use"
)

# Computer use tools
computer_tools = [
    {
        "type": "computer_20241022",
        "name": "computer",
        "display_width_px": 1920,
        "display_height_px": 1080,
        "display_number": 1
    },
    {
        "type": "bash_20241022",
        "name": "bash"
    }
]

def get_screenshot() -> str:
    # Your screenshot capture implementation
    # Returns base64-encoded PNG
    return "base64_screenshot_data_here"

def run_verified_computer_agent(task: str) -> str:
    messages = [{"role": "user", "content": task}]

    while True:
        response = client.beta.messages.create(
            model="claude-opus-4-5",
            max_tokens=4096,
            tools=computer_tools,
            messages=messages,
            betas=["computer-use-2024-10-22"]
        )

        # Verify the full response first
        try:
            verified_response = vex_client.verify(
                response=response,
                context={
                    "task_description": task,
                    "check_action_intent": True,
                    "screenshot_context": get_screenshot()
                }
            )
        except VexVerificationError as e:
            return f"Verification failed: {e.failure_mode}"

        if verified_response.stop_reason == "end_turn":
            return next((b.text for b in verified_response.content if hasattr(b, 'text')), "Done")

        tool_results = []
        for block in verified_response.content:
            if block.type == "tool_use":
                # Pre-action validation for each computer action
                try:
                    vex_client.verify_action(
                        tool_name=block.name,
                        tool_input=block.input,
                        screenshot=get_screenshot(),
                        allowed_actions=["left_click", "type", "scroll"],
                        blocked_selectors=["#delete-btn", ".destructive", "[data-action='remove']"],
                        require_confirmation_for=["submit", "purchase", "delete"]
                    )
                except VexActionBlockedError as e:
                    tool_results.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": f"Action blocked by safety policy: {e.reason}",
                        "is_error": True
                    })
                    continue

                # Execute the verified action
                # result = execute_computer_action(block.name, block.input)
                result = f"Executed {block.name}: {block.input}"
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": result
                })

        messages.append({"role": "assistant", "content": verified_response.content})
        messages.append({"role": "user", "content": tool_results})

result = run_verified_computer_agent("Open the dashboard and export the monthly report as CSV")
print(result)
